code.JavaScript:
const readline = require('readline');
const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});
rl.on('line', (input) => {
    const n = parseInt(input);
    if (n % 2 == 0) {
        console.log('Yes');
    } else {
        console.log('No');
    }
    rl.close();
});

